-- Regenerate with: node scripts/generate-backend-truth.mjs
-- Cross-project transfer: defer the stock move to RECEIPT (like a supplier order).
--
-- A B->A transfer takes real time + effort, so it should NOT land in the destination's
-- stock the instant it is placed. Instead, placing creates two linked 'placed' orders
-- (an 'out' order in the source project B and an 'in' order in the destination project A)
-- and moves NOTHING. When the goods arrive, the destination marks the 'in' order received,
-- which executes the actual move (B -qty, A +qty) atomically, fulfils A's procurement
-- item, and flips both orders to 'received'.
--
-- place_cross_project_stock_transfer (same signature) now does PLACEMENT only: it validates,
-- resolves the source items (and soft-checks current availability so you cannot place a
-- transfer the source plainly cannot cover), writes the two 'placed' orders + their lines,
-- and stores a self-contained execution payload on the 'in' order
-- (orders.transfer_payload). It writes no inventory_movements.
--
-- receive_cross_project_stock_transfer(p_transfer_group_id) does the move: it re-checks
-- authorization + availability, resolves/creates the destination item by canonical identity,
-- writes the two self-consistent movements (the OUT under B, the IN under A) and flips both
-- orders to 'received'. The IN (destination) movement carries the procurement_item_id so the
-- transfer counts toward A's need; the OUT (source) movement is a pure issue (NULL).
--
-- The source stock is NOT reserved between place and receive (product decision): if B is
-- depleted in the meantime, the receive raises a friendly "not enough stock".

alter table public.orders
  add column if not exists transfer_payload jsonb;

-- The source ('out') transfer line has no procurement_item_id to type it, so persist the resource
-- type ('material' | 'tool' | 'other') on the line itself for display.
alter table public.order_lines
  add column if not exists item_type text;

-- Stamp transfer movements with their group id so receipt idempotency can key on an IMMUTABLE
-- link (the group id) rather than order_line_id, which is ON DELETE SET NULL and severable by a
-- write-content user. Deleting a transfer order line then cannot orphan the guard's evidence.
alter table public.inventory_movements
  add column if not exists transfer_group_id uuid;
create index if not exists idx_inventory_movements_transfer_group_id
  on public.inventory_movements (transfer_group_id)
  where transfer_group_id is not null;

-- ---------------------------------------------------------------------------
-- PLACEMENT: create the two pending orders + execution payload, no movements.
-- The signature gains p_delivery_deadline (stored as both orders' delivery_due_at), so the
-- pending transfer carries an ETA like a supplier order. Drop the old 5-arg overload so the
-- 6-arg form is unambiguous.
-- ---------------------------------------------------------------------------
drop function if exists public.place_cross_project_stock_transfer(uuid, uuid, uuid, uuid, jsonb);

create or replace function public.place_cross_project_stock_transfer(
  p_from_project uuid,
  p_to_project uuid,
  p_from_location uuid,
  p_to_location uuid,
  p_lines jsonb,
  p_delivery_deadline timestamptz default null
)
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
  v_user uuid := auth.uid();
  v_group_id uuid := gen_random_uuid();
  v_now timestamptz := now();
  v_from_order_id uuid;
  v_to_order_id uuid;
  v_line jsonb;
  v_from_item_id uuid;
  v_proc_item uuid;
  v_title text;
  v_unit text;
  v_sku text;
  v_notes text;
  v_item_type text;
  v_qty numeric(14,3);
  v_price_cents bigint;
  v_total_cents bigint;
  v_available numeric(14,3);
  v_from_line_id uuid;
  v_to_line_id uuid;
  v_line_count integer := 0;
  v_payload jsonb := '[]'::jsonb;
begin
  -- 1. Authorization. Definer bypasses RLS, so check both projects explicitly.
  if v_user is null then
    raise exception 'Not authenticated' using errcode = '28000';
  end if;
  if p_from_project is null or p_to_project is null
     or p_from_location is null or p_to_location is null then
    raise exception 'Source and destination project and location are required'
      using errcode = '22023';
  end if;
  if p_from_project = p_to_project then
    raise exception 'Use the same-project transfer for moves within one project'
      using errcode = '22023';
  end if;
  if not public.can_use_project_stock(p_from_project) then
    raise exception 'Not authorized to move stock out of the source project'
      using errcode = '42501';
  end if;
  if not public.can_use_project_stock(p_to_project) then
    raise exception 'Not authorized to receive stock into the destination project'
      using errcode = '42501';
  end if;

  -- 2. Locations belong to their stated projects.
  if not exists (
    select 1 from public.inventory_locations
    where id = p_from_location and project_id = p_from_project
  ) then
    raise exception 'Source location does not belong to the source project'
      using errcode = '22023';
  end if;
  if not exists (
    select 1 from public.inventory_locations
    where id = p_to_location and project_id = p_to_project
  ) then
    raise exception 'Destination location does not belong to the destination project'
      using errcode = '22023';
  end if;

  if p_lines is null
     or jsonb_typeof(p_lines) <> 'array'
     or jsonb_array_length(p_lines) = 0 then
    raise exception 'No transfer lines provided' using errcode = '22023';
  end if;

  -- 3. Two linked 'placed' order headers. The 'out' order lives in the source project,
  --    the 'in' order in the destination. counterparty_location_id stores the OTHER side's
  --    location so receipt can recover both. Nothing moves yet.
  insert into public.orders (
    project_id, supplier_name, status, ordered_at, delivery_due_at, created_by,
    transfer_group_id, counterparty_project_id, counterparty_location_id, transfer_direction
  ) values (
    p_from_project, '', 'placed', v_now, p_delivery_deadline, v_user,
    v_group_id, p_to_project, p_to_location, 'out'
  )
  returning id into v_from_order_id;

  insert into public.orders (
    project_id, supplier_name, status, ordered_at, delivery_due_at, created_by,
    transfer_group_id, counterparty_project_id, counterparty_location_id, transfer_direction
  ) values (
    p_to_project, '', 'placed', v_now, p_delivery_deadline, v_user,
    v_group_id, p_from_project, p_from_location, 'in'
  )
  returning id into v_to_order_id;

  -- 4. Per line: resolve the SOURCE item, soft-check availability, write paired order lines,
  --    and record a self-contained execution entry in the payload.
  for v_line in select value from jsonb_array_elements(p_lines)
  loop
    v_from_item_id := nullif(v_line ->> 'from_item_id', '')::uuid;
    v_proc_item := nullif(v_line ->> 'procurement_item_id', '')::uuid;
    v_title := trim(coalesce(v_line ->> 'title', ''));
    v_unit := trim(coalesce(v_line ->> 'unit', ''));
    v_sku := nullif(trim(coalesce(v_line ->> 'sku', '')), '');
    v_notes := nullif(trim(coalesce(v_line ->> 'spec', '')), '');
    v_item_type := nullif(v_line ->> 'item_type', '');
    v_qty := coalesce((v_line ->> 'qty')::numeric, 0);
    v_price_cents := nullif(v_line ->> 'actual_unit_price_cents', '')::numeric::bigint;

    if v_qty <= 0 then
      raise exception 'Quantity must be positive for "%"', coalesce(nullif(v_title, ''), 'item')
        using errcode = '22023';
    end if;

    -- The procurement need belongs to the DESTINATION project.
    if v_proc_item is not null
       and not exists (
         select 1 from public.procurement_items
         where id = v_proc_item and project_id = p_to_project
       ) then
      raise exception 'Procurement item % is not in the destination project', v_proc_item
        using errcode = '22023';
    end if;

    -- Resolve the SOURCE item in p_from_project (explicit id, else by identity). Capture the
    -- canonical title/unit/sku/notes from the source row for the receipt's destination match.
    if v_from_item_id is not null then
      select ii.title, ii.unit, ii.sku, ii.notes
      into v_title, v_unit, v_sku, v_notes
      from public.inventory_items ii
      where ii.id = v_from_item_id and ii.project_id = p_from_project;
      if not found then
        raise exception 'Source item % is not in the source project', v_from_item_id
          using errcode = '22023';
      end if;
    else
      if v_unit = '' then
        raise exception 'Unit is required for "%"', coalesce(nullif(v_title, ''), 'item')
          using errcode = '22023';
      end if;
      select ii.id, ii.title, ii.unit, ii.sku, ii.notes
      into v_from_item_id, v_title, v_unit, v_sku, v_notes
      from public.inventory_items ii
      where ii.project_id = p_from_project
        and ii.identity_key = public.inventory_item_identity(v_title, v_notes, v_unit)
      order by ii.created_at asc, ii.id asc
      limit 1;
      if not found then
        raise exception 'Item "%" (%) was not found in the source project',
          v_title, coalesce(v_sku, v_unit)
          using errcode = '22023';
      end if;
    end if;

    -- Soft availability check at placement (the hard check + balance CHECK run at receipt).
    select coalesce(sum(ib.quantity), 0)
    into v_available
    from public.inventory_balances ib
    where ib.project_id = p_from_project
      and ib.inventory_item_id = v_from_item_id
      and ib.inventory_location_id = p_from_location;
    if v_available < v_qty then
      raise exception 'Not enough stock to transfer "%": % available, % requested',
        v_title, v_available, v_qty
        using errcode = 'P0001';
    end if;

    v_total_cents := case
      when v_price_cents is null then null
      else round(v_price_cents * v_qty)::bigint
    end;

    -- Paired order lines (for each project's order detail). Source line is a pure issue
    -- (procurement_item_id NULL); destination line carries the fulfilled need.
    insert into public.order_lines (
      order_id, procurement_item_id, item_type, title, quantity, unit, unit_price_cents, total_price_cents
    ) values (
      v_from_order_id, null, v_item_type, v_title, v_qty, v_unit, v_price_cents, v_total_cents
    )
    returning id into v_from_line_id;

    insert into public.order_lines (
      order_id, procurement_item_id, item_type, title, quantity, unit, unit_price_cents, total_price_cents
    ) values (
      v_to_order_id, v_proc_item, v_item_type, v_title, v_qty, v_unit, v_price_cents, v_total_cents
    )
    returning id into v_to_line_id;

    v_payload := v_payload || jsonb_build_object(
      'from_order_line_id', v_from_line_id,
      'to_order_line_id', v_to_line_id,
      'source_inventory_item_id', v_from_item_id,
      'dest_procurement_item_id', v_proc_item,
      'qty', v_qty,
      'title', v_title,
      'unit', v_unit,
      'sku', v_sku,
      'notes', v_notes
    );
    v_line_count := v_line_count + 1;
  end loop;

  -- Stash the execution payload on the 'in' order so receipt is self-contained.
  update public.orders set transfer_payload = v_payload where id = v_to_order_id;

  return jsonb_build_object(
    'transfer_group_id', v_group_id,
    'from_order_id', v_from_order_id,
    'to_order_id', v_to_order_id,
    'from_project_id', p_from_project,
    'to_project_id', p_to_project,
    'line_count', v_line_count,
    'status', 'placed'
  );
end;
$$;

-- ---------------------------------------------------------------------------
-- RECEIPT: execute the move (OUT under source, IN under destination), mark received.
-- ---------------------------------------------------------------------------
create or replace function public.receive_cross_project_stock_transfer(p_transfer_group_id uuid)
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
  v_user uuid := auth.uid();
  v_from_project uuid;
  v_to_project uuid;
  v_from_location uuid;
  v_to_location uuid;
  v_from_order_id uuid;
  v_to_order_id uuid;
  v_to_status text;
  v_payload jsonb;
  v_entry jsonb;
  v_from_item_id uuid;
  v_to_item_id uuid;
  v_proc_item uuid;
  v_qty numeric(14,3);
  v_title text;
  v_unit text;
  v_sku text;
  v_notes text;
  v_available numeric(14,3);
  v_line_count integer := 0;
begin
  if v_user is null then
    raise exception 'Not authenticated' using errcode = '28000';
  end if;
  if p_transfer_group_id is null then
    raise exception 'Transfer id is required' using errcode = '22023';
  end if;

  -- Load + lock the destination ('in') order; it carries the execution payload.
  select o.id, o.project_id, o.counterparty_project_id, o.counterparty_location_id,
         o.status, o.transfer_payload
  into v_to_order_id, v_to_project, v_from_project, v_from_location, v_to_status, v_payload
  from public.orders o
  where o.transfer_group_id = p_transfer_group_id
    and o.transfer_direction = 'in'
  for update;
  if not found then
    raise exception 'Cross-project transfer not found' using errcode = 'P0002';
  end if;

  select o.id, o.counterparty_location_id
  into v_from_order_id, v_to_location
  from public.orders o
  where o.transfer_group_id = p_transfer_group_id
    and o.transfer_direction = 'out'
  for update;
  if not found then
    raise exception 'Cross-project transfer source order not found' using errcode = 'P0002';
  end if;

  -- Both locations come from the counterparty columns, which are ON DELETE SET NULL. If either
  -- location was deleted during the place->receive window, refuse loudly rather than write a
  -- location-less movement (which would silently credit a NULL-location balance bucket) or fail
  -- with a misleading "not enough stock" (a NULL source location matches zero balance rows).
  if v_from_location is null then
    raise exception 'The source location for this transfer was removed; it can no longer be received'
      using errcode = 'P0002';
  end if;
  if v_to_location is null then
    raise exception 'The destination location for this transfer was removed; it can no longer be received'
      using errcode = 'P0002';
  end if;

  -- Authorization re-checked at receipt (definer bypasses RLS).
  if not public.can_use_project_stock(v_from_project) then
    raise exception 'Not authorized to move stock out of the source project'
      using errcode = '42501';
  end if;
  if not public.can_use_project_stock(v_to_project) then
    raise exception 'Not authorized to receive stock into the destination project'
      using errcode = '42501';
  end if;

  if v_to_status = 'received' then
    -- Idempotent: already received.
    return jsonb_build_object('transfer_group_id', p_transfer_group_id, 'status', 'received',
                              'already', true);
  end if;
  if v_to_status <> 'placed' then
    raise exception 'Transfer is not awaiting receipt (status %)', v_to_status
      using errcode = '22023';
  end if;
  if v_payload is null or jsonb_typeof(v_payload) <> 'array' then
    raise exception 'Transfer has no execution payload' using errcode = 'P0001';
  end if;

  -- Robust idempotency: gate replay on the existence of movements stamped with this transfer's
  -- group id, NOT on the mutable status/payload columns. A destination writer can restore both
  -- status='placed' and transfer_payload via the orders_update RLS surface (defeating the guards
  -- above), but cannot un-stamp the first receipt's movements; and unlike order_line_id, the
  -- transfer_group_id link is not severable by deleting an order line. (Deleting the movements
  -- themselves reverses their balance deltas symmetrically, so that path stays net-neutral.)
  if exists (
    select 1 from public.inventory_movements m
    where m.transfer_group_id = p_transfer_group_id
  ) then
    return jsonb_build_object('transfer_group_id', p_transfer_group_id, 'status', 'received',
                              'already', true);
  end if;

  -- Execute each line: resolve/create the destination item, then write the paired movements.
  for v_entry in select value from jsonb_array_elements(v_payload)
  loop
    v_from_item_id := nullif(v_entry ->> 'source_inventory_item_id', '')::uuid;
    v_proc_item := nullif(v_entry ->> 'dest_procurement_item_id', '')::uuid;
    v_qty := coalesce((v_entry ->> 'qty')::numeric, 0);
    v_title := trim(coalesce(v_entry ->> 'title', ''));
    v_unit := trim(coalesce(v_entry ->> 'unit', ''));
    v_sku := nullif(trim(coalesce(v_entry ->> 'sku', '')), '');
    v_notes := nullif(trim(coalesce(v_entry ->> 'notes', '')), '');

    -- A sanctioned placement never writes a null source item or non-positive qty; a payload entry
    -- that has one is malformed/tampered, so fail loudly rather than silently skip it while still
    -- flipping the orders to 'received' (which would report a partial move as complete).
    if v_from_item_id is null or v_qty <= 0 then
      raise exception 'Malformed transfer line (missing source item or non-positive quantity)'
        using errcode = '22023';
    end if;

    -- Re-read the source item's canonical fields (it may have been edited since placement).
    select ii.title, ii.unit, ii.sku, ii.notes
    into v_title, v_unit, v_sku, v_notes
    from public.inventory_items ii
    where ii.id = v_from_item_id and ii.project_id = v_from_project;
    if not found then
      raise exception 'Source item % is no longer in the source project', v_from_item_id
        using errcode = '22023';
    end if;

    -- Hard availability check at the source location.
    select coalesce(sum(ib.quantity), 0)
    into v_available
    from public.inventory_balances ib
    where ib.project_id = v_from_project
      and ib.inventory_item_id = v_from_item_id
      and ib.inventory_location_id = v_from_location;
    if v_available < v_qty then
      raise exception 'Not enough stock to receive "%": % available, % requested',
        v_title, v_available, v_qty
        using errcode = 'P0001';
    end if;

    -- The destination procurement item may have been deleted since placement. Drop a now-dangling
    -- link (rather than aborting the whole receipt on the inventory_movements.procurement_item_id
    -- FK, which would strand the transfer): the stock still physically moves, just unlinked.
    if v_proc_item is not null
       and not exists (
         select 1 from public.procurement_items
         where id = v_proc_item and project_id = v_to_project
       ) then
      v_proc_item := null;
    end if;

    -- Resolve-or-create the DESTINATION item in p_to_project by canonical identity.
    select ii.id
    into v_to_item_id
    from public.inventory_items ii
    where ii.project_id = v_to_project
      and ii.identity_key = public.inventory_item_identity(v_title, v_notes, v_unit)
    order by ii.created_at asc, ii.id asc
    limit 1;
    if not found then
      insert into public.inventory_items (project_id, title, sku, unit, notes)
      values (v_to_project, v_title, v_sku, v_unit, v_notes)
      returning id into v_to_item_id;
    end if;

    -- OUT under the source project (pure issue, procurement_item_id NULL).
    insert into public.inventory_movements (
      project_id, inventory_item_id, inventory_location_id,
      order_line_id, procurement_item_id, transfer_group_id, movement_type, delta_qty, created_by
    ) values (
      v_from_project, v_from_item_id, v_from_location,
      nullif(v_entry ->> 'from_order_line_id', '')::uuid, null, p_transfer_group_id, 'transfer', -v_qty, v_user
    );

    -- IN under the destination project (carries the fulfilled procurement_item_id).
    insert into public.inventory_movements (
      project_id, inventory_item_id, inventory_location_id,
      order_line_id, procurement_item_id, transfer_group_id, movement_type, delta_qty, created_by
    ) values (
      v_to_project, v_to_item_id, v_to_location,
      nullif(v_entry ->> 'to_order_line_id', '')::uuid, v_proc_item, p_transfer_group_id, 'transfer', v_qty, v_user
    );

    v_line_count := v_line_count + 1;
  end loop;

  -- Clear the execution payload while marking received. 'received' is not enforced-terminal at the
  -- data layer (a raw status revert via RLS is possible), so a re-receive must find no payload and
  -- abort at the null-payload guard rather than replay the movements and double-move stock.
  update public.orders set status = 'received', transfer_payload = null, updated_at = now()
  where id in (v_from_order_id, v_to_order_id);

  return jsonb_build_object(
    'transfer_group_id', p_transfer_group_id,
    'from_order_id', v_from_order_id,
    'to_order_id', v_to_order_id,
    'from_project_id', v_from_project,
    'to_project_id', v_to_project,
    'line_count', v_line_count,
    'status', 'received'
  );
end;
$$;

revoke all on function public.place_cross_project_stock_transfer(uuid, uuid, uuid, uuid, jsonb, timestamptz) from public;
grant execute on function public.place_cross_project_stock_transfer(uuid, uuid, uuid, uuid, jsonb, timestamptz) to authenticated;
revoke all on function public.receive_cross_project_stock_transfer(uuid) from public;
grant execute on function public.receive_cross_project_stock_transfer(uuid) to authenticated;
